        desc_p2: "\u0421\u043e\u0437\u0434\u0430\u043d\u043d\u044b\u0439 \u043d\u0430 Python, \u043e\u043d \u0442\u0435\u0441\u0442\u0438\u0440\u0443\u0435\u0442 \u0443\u044f\u0437\u0432\u0438\u043c\u043e\u0441\u0442\u0438 \u043e\u0442\u0440\u0430\u0436\u0435\u043d\u043d\u043e\u0433\u043e, \u0441\u043e\u0445\u0440\u0430\u043d\u0435\u043d\u043d\u043e\u0433\u043e \u0438 DOM-\u043e\u0441\u043d\u043e\u0432\u0430\u043d\u043d\u043e\u0433\u043e XSS, \u0438\u043d\u0442\u0435\u0433\u0440\u0438\u0440\u0443\u044f\u0441\u044c \u0441 \u043a\u043e\u043d\u0432\u0435\u0439\u0435\u0440\u043e\u043c \u0432\u0435\u0431-\u0444\u0430\u0437\u0437\u0435\u0440\u0430.",
        h_usage: "\u0418\u0441\u043f\u043e\u043b\u044c\u0437\u043e\u0432\u0430\u043d\u0438\u0435",
